#include <stdio.h>
#include <time.h>

void log_error(const char *error_message) {
    time_t now;
    time(&now);
    struct tm *local = localtime(&now);
    
    printf("[%02d-%02d-%04d %02d:%02d:%02d] ERROR: %s\n", 
           local->tm_mday, local->tm_mon + 1, local->tm_year + 1900,
           local->tm_hour, local->tm_min, local->tm_sec, error_message);
}